        },
        {
            "label": "SHOULD / MUST",
            "color": "amber",
            "description": "–Ē–Ľ—Ź –Ņ–ĺ—Ä–į–ī –į–Ī–ĺ –ĺ–Ī–ĺ–≤ ľ—Ź–∑–ļ—Ė–≤ –∑ –≤–ł–Ī–ĺ—Ä–ĺ–ľ:",
            "examples": [
                {
                    "en": "Should I call or text you?",
                    "ua": "–ú–Ķ–Ĺ—Ė —ā–ĺ–Ī—Ė —ā–Ķ–Ľ–Ķ—Ą–ĺ–Ĺ—É–≤–į—ā–ł —á–ł –Ĺ–į–Ņ–ł—Ā–į—ā–ł?"
